const { ethers } = require('ethers');

class TokenSwapper {
  constructor(provider, signer, routerAddress) {
    this.provider = provider;
    this.signer = signer;
    this.routerAddress = routerAddress;
    this.router = new ethers.Contract(routerAddress, this.getRouterABI(), signer);
  }

  getRouterABI() {
    return [
      "function swapExactTokensForTokens(uint amountIn, uint amountOutMin, address[] calldata path, address to, uint deadline) external returns (uint[] memory amounts)",
      "function getAmountsOut(uint amountIn, address[] calldata path) external view returns (uint[] memory amounts)",
      "function approve(address spender, uint256 amount) external returns (bool)"
    ];
  }

  getTokenABI() {
    return [
      "function balanceOf(address account) external view returns (uint256)",
      "function approve(address spender, uint256 amount) external returns (bool)",
      "function allowance(address owner, address spender) external view returns (uint256)"
    ];
  }

  async getAmountsOut(amountIn, fromToken, toToken, path) {
    try {
      const amounts = await this.router.getAmountsOut(amountIn, path);
      return amounts;
    } catch (error) {
      console.error('Error getting amounts out:', error);
      throw error;
    }
  }

  async approveToken(tokenAddress, amount = ethers.constants.MaxUint256) {
    try {
      const token = new ethers.Contract(tokenAddress, this.getTokenABI(), this.signer);
      const tx = await token.approve(this.routerAddress, amount);
      await tx.wait();
      return tx;
    } catch (error) {
      console.error('Error approving token:', error);
      throw error;
    }
  }

  async isApproved(tokenAddress, amount = ethers.constants.MaxUint256) {
    try {
      const token = new ethers.Contract(tokenAddress, this.getTokenABI(), this.signer);
      const allowance = await token.allowance(await this.signer.getAddress(), this.routerAddress);
      return allowance.gte(amount);
    } catch (error) {
      console.error('Error checking approval:', error);
      return false;
    }
  }

  async swapTokens(amountIn, fromToken, toToken, path, recipient = null, deadline = null) {
    try {
      if (!recipient) {
        recipient = await this.signer.getAddress();
      }
      
      if (!deadline) {
        deadline = Math.floor(Date.now() / 1000) + 60 * 10; // 10 minutes from now
      }

      const tx = await this.router.swapExactTokensForTokens(
        amountIn,
        0, // amountOutMin, set to 0 for simplicity
        path,
        recipient,
        deadline
      );

      return await tx.wait();
    } catch (error) {
      console.error('Error swapping tokens:', error);
      throw error;
    }
  }

  async swapWithApproval(amountIn, fromToken, toToken, path, recipient = null, deadline = null) {
    try {
      const isApproved = await this.isApproved(fromToken);
      
      if (!isApproved) {
        await this.approveToken(fromToken);
      }

      return await this.swapTokens(amountIn, fromToken, toToken, path, recipient, deadline);
    } catch (error) {
      console.error('Error in swap with approval:', error);
      throw error;
    }
  }
}

